INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('latin', 'bachillerato', '{2}', 'Julio César y los Comentarios sobre la Guerra de las Galias',
'Los Commentarii de bello Gallico son el texto latino más frecuentemente utilizado en los cursos de latín escolar y universitario de todo el mundo, por varias razones: la claridad de su sintaxis, la sobriedad de su léxico, la casi total ausencia de recursos retóricos complicados y el interés histórico de su contenido. Fueron escritos por Cayo Julio César durante los años en que dirigió la conquista de la Galia (58-51 a.C.) y publicados en Roma como informes anuales al Senado, aunque con evidente intención propagandística personal. El estilo es tercera persona: César habla de sí mismo como Caesar, lo que crea una impresión aparente de objetividad histórica. La obra está dividida en ocho libros, de los cuales los siete primeros son obra del propio César y el octavo fue añadido después por su legado Aulo Hircio. El libro primero comienza con la célebre frase que todo estudiante latino conoce: Gallia est omnis divisa in partes tres, quarum unam incolunt Belgae, aliam Aquitani, tertiam qui ipsorum lingua Celtae, nostra Galli appellantur (Toda la Galia está dividida en tres partes, una de las cuales habitan los belgas, otra los aquitanos, la tercera los que en su lengua se llaman celtas y en la nuestra galos). La obra narra las campañas contra los helvecios, los germanos de Ariovisto, los belgas, los vénetos, las dos expediciones a Britania, los eburones, y finalmente la gran rebelión panceltica liderada por Vercingétorix, aplastada definitivamente en la batalla de Alesia en el 52 a.C. César utilizó estos comentarios para construir su imagen pública y legitimar el inmenso poder militar que iba acumulando frente al Senado.',
'[{"pregunta":"¿En cuántos libros se divide De bello Gallico?","opciones":["Cinco","Seis","Ocho","Diez"],"correcta":2},{"pregunta":"¿Quién escribió el libro VIII?","opciones":["César","Hircio","Cicerón","Asinio Polión"],"correcta":1},{"pregunta":"¿En qué persona gramatical habla César de sí mismo?","opciones":["Primera","Segunda","Tercera","Cuarta"],"correcta":2},{"pregunta":"¿Dónde derrotó César a Vercingétorix?","opciones":["Gergovia","Avarico","Alesia","Bibracte"],"correcta":2}]'::jsonb),

('latin', 'bachillerato', '{2}', 'Cicerón: las Catilinarias y la oratoria romana',
'Marco Tulio Cicerón (106-43 a.C.) es el máximo representante de la oratoria latina y uno de los escritores más influyentes de toda la literatura occidental. Nacido en Arpino, en una familia del orden ecuestre provincial, ascendió mediante su talento hasta el consulado en el año 63 a.C., convirtiéndose en homo novus, es decir, el primer miembro de su familia en alcanzar la más alta magistratura romana. Precisamente durante su consulado tuvo lugar el episodio más famoso de su vida política: la conjuración de Catilina. Lucio Sergio Catilina, noble arruinado y resentido, preparó un complot para derribar a la República mediante un levantamiento armado en Etruria y asesinatos en Roma. Cicerón, alertado por confidentes, desenmascaró el complot ante el Senado el 8 de noviembre del 63 a.C. en el templo de Júpiter Stator con el primero de sus cuatro discursos contra Catilina, las célebres Catilinarias. El comienzo de esta primera oración es probablemente el pasaje más citado de la literatura latina: Quousque tandem abutere, Catilina, patientia nostra? Quam diu etiam furor iste tuus nos eludet? (¿Hasta cuándo, Catilina, abusarás de nuestra paciencia? ¿Cuánto tiempo más ha de burlarse de nosotros esa furia tuya?). El discurso forzó a Catilina a huir de Roma; los demás conjurados fueron apresados y, tras un tenso debate en el que intervinieron César y Catón, ejecutados sin juicio regular. Esta decisión, aprobada gracias a la presión de Cicerón, le costaría años después el exilio bajo el tribunado de Clodio. Cicerón murió asesinado en el 43 a.C. por sicarios de Marco Antonio.',
'[{"pregunta":"¿Qué año fue cónsul Cicerón?","opciones":["83 a.C.","63 a.C.","43 a.C.","23 a.C."],"correcta":1},{"pregunta":"¿Qué significa homo novus?","opciones":["Hombre joven","Primer miembro de la familia en llegar al consulado","Hombre recién llegado a Roma","Hombre sin linaje"],"correcta":1},{"pregunta":"¿Cuántas Catilinarias escribió Cicerón?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":2},{"pregunta":"¿Cómo empieza la primera Catilinaria?","opciones":["Arma virumque cano","Quousque tandem abutere, Catilina","Veni, vidi, vici","Alea iacta est"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'Virgilio y la Eneida: la epopeya nacional romana',
'Publio Virgilio Marón (70-19 a.C.) es considerado el más grande poeta romano y su obra maestra, la Eneida, la epopeya nacional por excelencia de Roma. Escrita por encargo indirecto del emperador Augusto durante los últimos once años de vida del poeta, entre el 29 y el 19 a.C., la Eneida recoge en doce libros las aventuras de Eneas, príncipe troyano hijo de Anquises y de Venus, que escapa de la Troya incendiada por los griegos con su padre, su hijo Ascanio y los penates de la ciudad, y viaja por el Mediterráneo buscando la tierra prometida por los dioses donde fundar una nueva patria. Tras múltiples aventuras (los harpías, el escala en Cartago con la trágica historia de amor con la reina Dido, que acaba suicidándose; la bajada al inframundo guiado por la Sibila de Cumas, donde se le revela el futuro glorioso de Roma; y las guerras en el Lacio contra Turno, rey de los rútulos), Eneas logra establecerse en Italia, uniendo a troyanos y latinos en el pueblo que dará origen, siglos más tarde, a Roma. La Eneida combina claros modelos griegos: los seis primeros libros recuerdan a la Odisea de Homero (viajes y aventuras), y los seis últimos a la Ilíada (guerra y batallas). Pero Virgilio imprime al poema una profundidad moral, un tono elegíaco y una conciencia del coste humano de la historia que superan a sus modelos. La epopeya glorifica el destino providencial de Roma y la misión civilizadora del pueblo romano, sintetizada en los célebres versos: Tu regere imperio populos, Romane, memento (hae tibi erunt artes), pacique imponere morem, parcere subiectis et debellare superbos (Tú, romano, acuérdate de regir con tu imperio a los pueblos: estas serán tus artes: imponer la ley de la paz, perdonar a los sometidos y abatir a los soberbios).',
'[{"pregunta":"¿Cuántos libros tiene la Eneida?","opciones":["Seis","Nueve","Doce","Quince"],"correcta":2},{"pregunta":"¿Quién es el protagonista?","opciones":["Ulises","Aquiles","Eneas","Héctor"],"correcta":2},{"pregunta":"¿Quién se suicida tras el abandono de Eneas?","opciones":["Lavinia","Dido","Creusa","Camila"],"correcta":1},{"pregunta":"¿Qué modelos griegos sigue la Eneida?","opciones":["Tragedia y comedia","Ilíada y Odisea","Teogonía y Trabajos","Himnos homéricos"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'Ovidio y las Metamorfosis',
'Publio Ovidio Nasón (43 a.C. - 17 d.C.) es, junto con Virgilio y Horacio, uno de los tres grandes poetas de la edad de oro de la literatura latina, la llamada edad de Augusto. A diferencia de sus contemporáneos, Ovidio no mantuvo una relación tan estrecha con el círculo imperial y acabó siendo desterrado por el propio Augusto el año 8 d.C. a Tomis (actual Constanza, en la costa del Mar Negro), por razones que siguen sin estar claras del todo. En el exilio murió sin lograr el regreso. Su obra se divide en tres grandes periodos. El primero es la poesía amorosa juvenil y brillante: los Amores, las Heroidas (cartas imaginarias de heroínas mitológicas a sus amados), el Arte de amar (Ars amatoria), tratado irónico sobre la seducción. El segundo es la madurez, centrada en dos grandes obras: las Metamorfosis, poema en quince libros y más de 12.000 versos que recopila transformaciones mitológicas desde el origen del universo hasta la apoteosis de Julio César; y los Fastos, calendario religioso romano inacabado en seis libros. El tercer periodo corresponde al exilio, con las Tristia y las Epistulae ex Ponto, cartas elegíacas llenas de melancolía. Las Metamorfosis, sin duda su obra maestra, despliegan una enorme variedad de historias (Apolo y Dafne, Narciso y Eco, Piramo y Tisbe, Orfeo y Eurídice, Filemón y Baucis, etc.) unidas por el hilo común de las transformaciones, que sugieren una visión del universo como flujo constante. Se convirtieron en la fuente mitológica por excelencia de toda la literatura y el arte occidentales: sin las Metamorfosis no habría buena parte del Renacimiento, de la ópera barroca ni de la poesía moderna.',
'[{"pregunta":"¿Cuántos libros tienen las Metamorfosis?","opciones":["Diez","Doce","Quince","Veinte"],"correcta":2},{"pregunta":"¿Dónde fue desterrado Ovidio?","opciones":["Marsella","Tomis","Atenas","Alejandría"],"correcta":1},{"pregunta":"¿Qué obra trata sobre la seducción con ironía?","opciones":["Amores","Heroidas","Ars amatoria","Fastos"],"correcta":2},{"pregunta":"¿Qué obras escribió en el exilio?","opciones":["Amores","Tristia y Epistulae ex Ponto","Metamorfosis","Fastos"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'La comedia latina: Plauto y Terencio',
'La comedia fue, junto con la lírica, uno de los géneros que los romanos tomaron de los griegos adaptándolo a su propia sensibilidad. Los modelos eran las comedias de la llamada Comedia Nueva griega, especialmente las de Menandro, Filemón y Difilo, escritores del siglo IV y III a.C. cuyas obras, muy moralistas y de enredo, se centraban en situaciones domésticas y personajes tipificados. Los dos grandes comediógrafos latinos que conservamos son Plauto y Terencio, muy distintos entre sí. Tito Maccio Plauto (c. 254-184 a.C.) es el autor latino más antiguo del que conservamos obras completas: unas veinte comedias, sobre un total estimado de 130 atribuidas en la Antigüedad. Plauto adapta libremente los originales griegos combinándolos con elementos populares italianos, lo que se ha llamado contaminatio. Su lenguaje es vivaz, lleno de juegos de palabras, latinismos vulgares y recursos cómicos de gran efecto. Sus personajes son tipos reconocibles: el viejo avaro, el joven enamorado, la cortesana, el soldado fanfarrón (Miles gloriosus), el esclavo astuto (Pseudolus), el parásito glotón. Obras fundamentales son Amphitruo, Miles gloriosus, Aulularia (la comedia del avaro, fuente de Molière), Pseudolus, Menaechmi y Mostellaria. Publio Terencio Afer (c. 185-159 a.C.), nacido en Cartago y llegado a Roma como esclavo, es más refinado y culto que Plauto. Sus seis comedias conservadas (Andria, Eunuchus, Heauton Timorumenos, Phormio, Hecyra, Adelphoe) se adhieren más fielmente a los originales griegos, especialmente a Menandro, y se caracterizan por un lenguaje pulido, un tratamiento más psicológico de los personajes y una preocupación humana sintetizada en el célebre verso: Homo sum, humani nihil a me alienum puto (Hombre soy, nada humano considero ajeno a mí).',
'[{"pregunta":"¿Qué comedia griega sirvió de modelo a los latinos?","opciones":["La Comedia Antigua","La Comedia Nueva","El drama satírico","El mimo"],"correcta":1},{"pregunta":"¿Qué autor griego fue el modelo principal?","opciones":["Aristófanes","Menandro","Cratino","Éupolis"],"correcta":1},{"pregunta":"¿Cuántas comedias conservamos de Terencio?","opciones":["Cuatro","Cinco","Seis","Ocho"],"correcta":2},{"pregunta":"¿De quién es el verso Homo sum, humani nihil a me alienum puto?","opciones":["Plauto","Terencio","Cicerón","Horacio"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'Horacio y la lírica latina',
'Quinto Horacio Flaco (65-8 a.C.), hijo de un liberto de Venusia (Apulia), es con Virgilio el gran poeta augusteo y el maestro de la lírica romana. Tras estudiar en Roma y Atenas, combatió del lado republicano en la batalla de Filipos (42 a.C.), pero tras la derrota se acogió a la amnistía y regresó a Roma, donde se ganó la vida modestamente como scriba quaestorius. La amistad con Virgilio le abrió las puertas del círculo literario de Mecenas, mecenas por excelencia de las letras latinas y consejero de Augusto, quien le regaló en el 33 a.C. una finca en la Sabina que le permitió dedicarse plenamente a la poesía. La obra de Horacio es variada y abarca varios géneros. Las Sátiras (Sermones), primeras composiciones, son poemas conversacionales y moralistas en hexámetros, herederos de la sátira romana de Lucilio. Los Épodos, escritos a continuación, introducen la métrica yámbica griega siguiendo a Arquíloco. Pero las obras mayores son las Odas (Carmina), cuatro libros de poesía lírica en metros griegos variadísimos (alcaico, sáfico, asclepiadeo) en los que Horacio alcanza la máxima perfección formal de la literatura latina. Los temas de las Odas son universales: el carpe diem (aprovecha el día), el aurea mediocritas (justa medianía), la amistad, el amor, el vino, el paso del tiempo, la crítica política suave y la alabanza de Augusto. La célebre Oda Exegi monumentum aere perennius (He erigido un monumento más duradero que el bronce) cierra el libro III y afirma la inmortalidad del poeta a través de su obra. Horacio escribió también Epístolas y el Arte poética, tratado sobre literatura que influyó en todo el clasicismo europeo.',
'[{"pregunta":"¿Quién fue el mecenas de Horacio?","opciones":["Augusto","Mecenas","Agripa","Cayo Mario"],"correcta":1},{"pregunta":"¿Cuántos libros de Odas escribió?","opciones":["Dos","Tres","Cuatro","Cinco"],"correcta":2},{"pregunta":"¿Qué famoso lema horaciano invita a aprovechar el día?","opciones":["Alea iacta est","Carpe diem","Tempus fugit","Ars longa"],"correcta":1},{"pregunta":"¿Qué tratado literario escribió Horacio?","opciones":["De oratore","Ars poetica","Retórica","Poética"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'La historiografía latina: Salustio, Livio y Tácito',
'La historiografía romana es uno de los géneros más importantes y originales de la literatura latina. Surge en la Roma republicana influida por los modelos griegos (especialmente Tucídides), pero incorpora rasgos propios como el enfoque moralizante, la preocupación por los grandes personajes y la reflexión sobre el destino de Roma. Los tres grandes historiadores latinos son Salustio, Tito Livio y Tácito. Cayo Salustio Crispo (86-35 a.C.) es el primer gran historiador latino cuyas obras conservamos completas. Partidario de César, tras una carrera política manchada por escándalos se retiró a escribir dos monografías: De coniuratione Catilinae, sobre la conjura de Catilina, y De bello Iugurthino, sobre la guerra contra el rey númida Yugurta. Su estilo, deliberadamente arcaizante y conciso, imita el de Tucídides y ofrece una visión pesimista y moralizante de la decadencia romana. Tito Livio (59 a.C. - 17 d.C.), padua, dedicó cuarenta años a escribir una colosal historia de Roma desde sus orígenes legendarios hasta la muerte de Druso en el 9 a.C., titulada Ab Urbe condita libri y compuesta originalmente por 142 libros, de los que se conservan 35. Su estilo, elegante y lleno de patetismo, exaltaba las virtudes primitivas del pueblo romano y pretendía estimular la regeneración moral en tiempos de Augusto. Cornelio Tácito (c. 55-120 d.C.), amigo de Plinio el Joven, es el más grande prosista latino y el gran historiador del Imperio. Sus obras principales son los Annales (sobre los sucesores de Augusto), las Historiae (sobre los Flavios), la Germania (sobre los pueblos germanos), la Agricola (biografía de su suegro, gobernador de Britania) y el Dialogus de oratoribus. Su estilo es denso, conciso y amargo, con una clara animadversión contra los emperadores tiránicos.',
'[{"pregunta":"¿Qué obras escribió Salustio?","opciones":["Dos epopeyas","Dos monografías históricas","Tres diálogos","Cuatro comentarios"],"correcta":1},{"pregunta":"¿Cuántos libros escribió Livio de su historia?","opciones":["30","70","142","200"],"correcta":2},{"pregunta":"¿Qué obra de Tácito trata sobre los germanos?","opciones":["Anales","Historias","Germania","Agricola"],"correcta":2},{"pregunta":"¿Cómo se titula la historia de Livio?","opciones":["Ab Urbe condita","De rerum natura","Historiae","Res gestae"],"correcta":0}]'::jsonb),

('latin', 'bachillerato', '{2}', 'Séneca y el estoicismo romano',
'Lucio Anneo Séneca (c. 4 a.C. - 65 d.C.), nacido en Córdoba (Hispania), es el filósofo latino más influyente y uno de los representantes más destacados del estoicismo romano. Hijo del retórico Séneca el Viejo, se trasladó joven a Roma donde inició una carrera política y literaria interrumpida por el exilio en Córcega durante ocho años bajo el emperador Claudio. Repuesto gracias a Agripina, fue nombrado preceptor del joven Nerón, y tras el ascenso de este al trono en el 54 d.C. se convirtió en uno de los hombres más poderosos del Imperio durante los primeros años del reinado, el llamado quinquenio feliz. Sin embargo, el progresivo enfrentamiento con Nerón le obligó a retirarse de la política, y en el año 65 fue obligado a suicidarse tras ser acusado de participar en la conjura de Pisón, episodio descrito dramáticamente por Tácito en los Anales. Su obra abarca dos grandes ámbitos: el filosófico y el teatral. En el primero destacan los Diálogos morales (De ira, De brevitate vitae, De providentia, De vita beata, De tranquillitate animi, De clementia), las 124 Epistulae morales ad Lucilium (el tratado de ética más influyente del estoicismo romano) y las Quaestiones naturales (sobre ciencia natural). Séneca adapta la doctrina estoica griega a la sensibilidad romana, insistiendo en la necesidad de dominar las pasiones, aceptar el destino (amor fati), practicar la virtud como único bien auténtico y recordar cotidianamente la brevedad de la vida y la inevitabilidad de la muerte. En el ámbito teatral escribió nueve tragedias de tema griego (Medea, Fedra, Tiestes, Edipo, Las troyanas, Agamenón, Hércules furioso, Hércules en el Oeta, Las fenicias), escritas probablemente para ser recitadas, no representadas.',
'[{"pregunta":"¿Dónde nació Séneca?","opciones":["Roma","Córdoba","Sevilla","Cartago"],"correcta":1},{"pregunta":"¿De qué emperador fue preceptor?","opciones":["Claudio","Nerón","Calígula","Vespasiano"],"correcta":1},{"pregunta":"¿Cuántas Epistulae morales escribió a Lucilio?","opciones":["50","86","124","200"],"correcta":2},{"pregunta":"¿A qué corriente filosófica pertenece?","opciones":["Epicureísmo","Estoicismo","Cinismo","Escepticismo"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'El derecho romano: fundamento jurídico de Occidente',
'El derecho romano es uno de los legados más duraderos y universales de la civilización romana y el fundamento histórico de todos los sistemas jurídicos occidentales modernos. Su desarrollo se extiende a lo largo de más de mil años, desde los orígenes legendarios de la ciudad hasta la caída del Imperio de Occidente. Puede dividirse en varias etapas. En el derecho arcaico, la primera codificación escrita fue la Ley de las Doce Tablas (lex duodecim tabularum), promulgada entre los años 451 y 450 a.C. tras la presión de los plebeyos por disponer de un código escrito que limitara la arbitrariedad de los magistrados patricios. Las tablas, grabadas en bronce y expuestas en el Foro, regulaban el procedimiento judicial, el derecho de familia, la propiedad, las sucesiones, los delitos y las penas. Durante la República y el Imperio, el derecho romano se desarrolló enormemente gracias a varias fuentes. Las leyes aprobadas por las asambleas (leges), los edictos de los pretores (edictum praetoris) que cada año adaptaban el derecho a las nuevas necesidades, los senatusconsulta (decisiones del Senado), las constituciones imperiales (rescripta, edicta) y, muy especialmente, la labor interpretativa de los iurisprudentes, juristas profesionales cuya autoridad era enorme (Papiniano, Ulpiano, Paulo, Gayo, Modestino). La gran codificación final tuvo lugar bajo el emperador bizantino Justiniano (527-565 d.C.), que encargó al jurista Triboniano la compilación de todo el derecho vigente. El resultado fue el Corpus iuris civilis, conjunto formado por el Código (leyes imperiales), el Digesto o Pandectas (extractos de los juristas clásicos), las Instituciones (manual para estudiantes) y las Novellae. Este corpus se convirtió en el texto básico de la ciencia jurídica europea a partir del siglo XII.',
'[{"pregunta":"¿Cuándo se promulgó la Ley de las XII Tablas?","opciones":["509 a.C.","451-450 a.C.","367 a.C.","287 a.C."],"correcta":1},{"pregunta":"¿Quién encargó el Corpus iuris civilis?","opciones":["Augusto","Constantino","Justiniano","Teodosio"],"correcta":2},{"pregunta":"¿Qué parte contiene extractos de los juristas clásicos?","opciones":["Código","Digesto","Instituciones","Novellae"],"correcta":1},{"pregunta":"¿Quién dirigió la compilación bajo Justiniano?","opciones":["Ulpiano","Papiniano","Triboniano","Gayo"],"correcta":2}]'::jsonb),

('latin', 'bachillerato', '{2}', 'La lírica amorosa: Catulo y los poetae novi',
'Cayo Valerio Catulo (c. 84-54 a.C.) es el mayor poeta lírico de la Roma republicana y una figura fascinante por la modernidad de su sensibilidad. Nacido en Verona en una familia acomodada, se trasladó pronto a Roma, donde se unió al grupo literario conocido como los poetae novi o neoteroi (poetas nuevos), jóvenes refinados que reaccionaban contra la poesía tradicional épica romana e importaban los ideales de la poesía alejandrina griega: brevedad, erudición, perfección formal, experimentación métrica y expresión intensa de sentimientos personales. La obra de Catulo se conserva íntegra gracias a un único manuscrito medieval hallado en Verona: 116 poemas de temática y extensión muy variables, desde epigramas de pocos versos hasta pequeñas epopeyas como el Epitalamio de Tetis y Peleo. Los más famosos son sin duda los dedicados a su amada Lesbia, seudónimo literario bajo el que se oculta Clodia, hermana del tribuno Clodio y una de las mujeres más escandalosas de la Roma tardorepublicana. Los poemas a Lesbia trazan toda la trayectoria de una pasión: del enamoramiento inicial con su encantador poema del gorrión (Vivamus, mea Lesbia, atque amemus), pasando por el éxtasis (Da mi basia mille, dame mil besos), hasta la desilusión, los celos, el desprecio y el intento amargo de olvido, con versos tan intensos como el famoso Odi et amo. Quare id faciam, fortasse requiris. Nescio, sed fieri sentio et excrucior (Odio y amo. Por qué lo hago, quizá te preguntas. No lo sé, pero lo siento y me atormenta). Catulo escribió también invectivas políticas contra César y Pompeyo, poemas a sus amigos, elegías funerales y ejercicios de erudición mitológica. Murió joven, con apenas treinta años.',
'[{"pregunta":"¿A qué grupo literario pertenecía Catulo?","opciones":["Los épicos","Los poetae novi o neoteroi","Los elegíacos","Los satíricos"],"correcta":1},{"pregunta":"¿Cómo llama Catulo a su amada en los poemas?","opciones":["Cynthia","Lesbia","Delia","Nemesis"],"correcta":1},{"pregunta":"¿Cuántos poemas se conservan de Catulo?","opciones":["50","100","116","150"],"correcta":2},{"pregunta":"¿Qué verso expresa los sentimientos contradictorios?","opciones":["Carpe diem","Odi et amo","Alea iacta est","Timeo danaos"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'La religión romana: dioses, culto y mitología',
'La religión romana tradicional era una religión politeísta, ritualista y cívica, profundamente ligada a la vida pública y a la familia. Los romanos creían en multitud de divinidades, algunas heredadas del fondo indoeuropeo, otras tomadas de los etruscos y, a partir del siglo III a.C., progresivamente identificadas con los dioses griegos mediante la llamada interpretatio Romana. Los doce grandes dioses del panteón, los Dii Consentes, eran Júpiter (Zeus), dios del cielo y padre de los dioses; Juno (Hera), esposa de Júpiter y protectora del matrimonio; Neptuno (Poseidón), dios del mar; Ceres (Deméter), diosa de la agricultura; Minerva (Atenea), diosa de la sabiduría; Apolo, dios de la poesía y la profecía; Diana (Ártemis), diosa de la caza; Marte (Ares), dios de la guerra; Venus (Afrodita), diosa del amor; Mercurio (Hermes), mensajero de los dioses; Vulcano (Hefesto), dios del fuego y los herreros; y Vesta (Hestia), diosa del hogar. Junto a estos grandes dioses existía una multitud de divinidades menores protectoras de cada aspecto de la vida: los Lares (protectores del hogar), los Penates (protectores de la despensa), los Manes (almas de los antepasados), el Genio familiar, Jano (dios de los inicios y las puertas, con dos caras), Saturno, Flora, Fauno y muchos más. El culto estaba organizado por colegios sacerdotales (pontífices, augures, flámines, vestales) y regulado por un calendario estricto de festividades. La ritualidad era lo esencial: el do ut des (te doy para que me des) expresaba la relación contractual con los dioses. A partir del siglo I d.C. se introdujeron cultos orientales (Isis, Cibeles, Mitra) y finalmente el cristianismo, que transformaría radicalmente la religiosidad del Imperio.',
'[{"pregunta":"¿Cómo se llamaba el principio que regía el culto romano?","opciones":["Amor fati","Do ut des","Carpe diem","Pacta sunt servanda"],"correcta":1},{"pregunta":"¿Quiénes eran los Lares?","opciones":["Dioses celestes","Almas de antepasados","Protectores del hogar","Dioses del inframundo"],"correcta":2},{"pregunta":"¿Cuántos eran los Dii Consentes?","opciones":["Nueve","Diez","Doce","Quince"],"correcta":2},{"pregunta":"¿Qué diosa custodiaba el hogar?","opciones":["Ceres","Minerva","Vesta","Juno"],"correcta":2}]'::jsonb),

('latin', 'bachillerato', '{2}', 'Las etapas de la literatura latina',
'La literatura latina, aunque más tardía que la griega (comienza propiamente en el siglo III a.C. tras la conquista romana de la Magna Grecia), alcanzó cotas propias de gran originalidad y se convirtió en el referente cultural de todo el Occidente medieval y moderno. Se divide convencionalmente en varias etapas. La literatura arcaica o preclásica (siglo III - 80 a.C.) comienza con Livio Andrónico, liberto griego que tradujo la Odisea al latín hacia el 240 a.C., y se desarrolla con Nevio, Ennio (padre de la épica latina con sus Annales), Plauto y Terencio (comedia) y Catón el Viejo (prosa histórica y tratados agrícolas). La edad de oro corresponde al periodo ciceroniano (80-30 a.C.) y al augusteo (30 a.C. - 14 d.C.), los años de máximo esplendor literario. En el periodo ciceroniano destacan Cicerón (oratoria y filosofía), César (comentarios), Lucrecio (poema filosófico De rerum natura, expositor del epicureísmo), Catulo y los poetae novi. En el periodo augusteo brillan Virgilio (Eneida, Geórgicas, Bucólicas), Horacio, Ovidio, Tito Livio y los elegíacos Tibulo y Propercio. La edad de plata o literatura imperial (14-117 d.C.) produce obras magníficas aunque a veces marcadas por la retórica y el pesimismo: Séneca (filosofía y tragedia), Lucano (Farsalia, épica sobre la guerra civil), Petronio (Satiricón, novela picaresca), Quintiliano (Institutio oratoria), Marcial (epigramas), Juvenal (sátiras), Plinio el Joven (cartas), Tácito, Suetonio (Vidas de los Doce Césares). Finalmente, la literatura tardía (siglos II-V d.C.) incluye autores paganos como Apuleyo (El asno de oro) y cristianos como Tertuliano, San Jerónimo (traductor de la Vulgata) y San Agustín (Confesiones, De civitate Dei).',
'[{"pregunta":"¿Quién tradujo la Odisea al latín?","opciones":["Ennio","Livio Andrónico","Nevio","Plauto"],"correcta":1},{"pregunta":"¿Qué autor escribió De rerum natura?","opciones":["Cicerón","Lucrecio","Virgilio","Séneca"],"correcta":1},{"pregunta":"¿De qué periodo es el Satiricón de Petronio?","opciones":["Arcaico","Ciceroniano","Edad de plata","Tardío"],"correcta":2},{"pregunta":"¿Quién tradujo la Biblia al latín?","opciones":["San Agustín","San Jerónimo","Tertuliano","Ambrosio"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'Las instituciones políticas romanas',
'La organización política de la Roma republicana es uno de los ejemplos más estudiados en la historia del derecho constitucional. Tras la expulsión del último rey Tarquino el Soberbio en el año 509 a.C., los romanos instauraron un sistema conocido como res publica (cosa pública), cuidadosamente diseñado para evitar el retorno a la tiranía mediante un sistema de equilibrios entre tres grandes elementos: las magistraturas, el Senado y las asambleas populares. Las magistraturas eran cargos públicos caracterizados por ser electivos (elegidos por las asambleas), colegiados (ocupados por varios titulares simultáneamente para limitarse mutuamente), anuales (duraban un año) y gratuitos (no recibían sueldo). La carrera política ordinaria, el cursus honorum, implicaba ascender progresivamente desde cargos menores (cuestura, edilidad) hasta los mayores (pretura, consulado, censura). Los dos cónsules eran los magistrados supremos, con amplios poderes militares y civiles; los pretores administraban justicia; los cuestores gestionaban las finanzas; los ediles se ocupaban de la ciudad; los censores realizaban el censo y vigilaban las costumbres. En situaciones de emergencia se nombraba un dictador con poderes absolutos por un máximo de seis meses. Los tribunos de la plebe, instituidos tras las luchas patricio-plebeyas, protegían a los plebeyos mediante el derecho de veto (intercessio) contra las decisiones de otros magistrados. El Senado, compuesto por unos trescientos exmagistrados nombrados por los censores, era el órgano consultivo fundamental y dirigía de hecho la política exterior, financiera y religiosa. Las asambleas populares (comitia) reunían a los ciudadanos para votar leyes, elegir magistrados y ejercer funciones judiciales. Este equilibrio se rompería con las guerras civiles del siglo I a.C. y desembocaría en el Principado augusteo.',
'[{"pregunta":"¿En qué año se instauró la República?","opciones":["509 a.C.","450 a.C.","390 a.C.","264 a.C."],"correcta":0},{"pregunta":"¿Cómo se llamaba la carrera política ordinaria?","opciones":["Via magistratus","Cursus honorum","Dignitas","Imperium"],"correcta":1},{"pregunta":"¿Qué poder especial tenían los tribunos de la plebe?","opciones":["Veto (intercessio)","Censura","Imperium","Auspicia"],"correcta":0},{"pregunta":"¿Cuánto duraban las magistraturas ordinarias?","opciones":["Un año","Dos años","Tres años","Cinco años"],"correcta":0}]'::jsonb),

('latin', 'bachillerato', '{2}', 'La familia romana: pater familias y matrimonio',
'La familia romana era una institución muy diferente a la nuestra, regida por principios jurídicos, religiosos y sociales profundamente arraigados. La palabra familia no designaba solo a los parientes consanguíneos, sino a todo el conjunto de personas y bienes sometidos a la autoridad del pater familias, incluyendo a la esposa, los hijos, los esclavos, los clientes y el patrimonio. El pater familias, cabeza absoluta del grupo, era el varón de mayor edad con plena capacidad jurídica y ejercía sobre los demás miembros la patria potestas, poder originalmente sin límites que incluía incluso el derecho de vida y muerte (ius vitae necisque), aunque en la práctica histórica este derecho cayó en desuso muy pronto. El pater era el único propietario del patrimonio familiar, el responsable del culto doméstico (Lares, Penates, Vesta) y el que daba el nombre a los miembros del grupo. Los hijos eran alieni iuris (sometidos a la autoridad de otro) hasta la muerte del padre, momento en que se convertían en sui iuris (dueños de su propio derecho). El matrimonio romano (iustum matrimonium) se basaba en el consentimiento continuado de los esposos y en la affectio maritalis. Existían dos modalidades: el matrimonio cum manu, en el que la esposa pasaba a estar bajo la potestad del marido o de su pater familias, abandonando la familia paterna; y el matrimonio sine manu, en el que la esposa permanecía bajo la autoridad de su padre originario. A lo largo del Imperio, la segunda modalidad se fue imponiendo, lo que dio a las mujeres romanas mayor autonomía jurídica y económica. El divorcio, siempre aceptado en Roma, era muy frecuente en los últimos siglos republicanos y podía ser iniciado por cualquiera de los cónyuges.',
'[{"pregunta":"¿Qué significa patria potestas?","opciones":["Poder del padre de la patria","Autoridad del pater familias sobre su familia","Potestad senatorial","Dictadura temporal"],"correcta":1},{"pregunta":"¿Cómo se llamaba el hijo sometido aún a potestad?","opciones":["Sui iuris","Alieni iuris","Pater familias","Dominus"],"correcta":1},{"pregunta":"¿Qué matrimonio mantenía a la esposa bajo su padre originario?","opciones":["Cum manu","Sine manu","Confarreatio","Coemptio"],"correcta":1},{"pregunta":"¿En qué se basaba el iustum matrimonium?","opciones":["Contrato escrito","Consentimiento y affectio maritalis","Dote","Adquisición"],"correcta":1}]'::jsonb);

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('latin', 'bachillerato', '{2}', 'César y la Guerra Civil: Alea iacta est',
'La Guerra Civil entre Julio César y Pompeyo (49-45 a.C.) es uno de los conflictos más decisivos de toda la historia romana y marca el fin efectivo de la República. Sus causas se remontan a años atrás: la disolución del Primer Triunvirato (César, Pompeyo, Craso), la muerte de Julia (hija de César y esposa de Pompeyo) en el 54 a.C. y la de Craso en Carras (53 a.C.), así como las sospechas crecientes del Senado respecto al poder acumulado por César durante sus campañas en la Galia. A finales del año 50 a.C., el Senado, influido por Pompeyo, exigió a César que licenciara sus legiones antes de regresar a Roma, lo que en la práctica significaba entregarse indefenso a sus enemigos. César se negó. En la madrugada del 10 al 11 de enero del año 49 a.C., al frente de una de sus legiones, cruzó el pequeño río Rubicón, frontera entre la Galia Cisalpina (su provincia) y la Italia propiamente dicha. Cruzar armado la frontera de Italia constituía legalmente un acto de guerra contra el Estado. Se cuenta que, al pasar el río, César pronunció la célebre frase Alea iacta est (La suerte está echada), palabras que resumen el momento sin retorno. En pocas semanas, la Italia se entregó a César casi sin resistencia. Pompeyo y la mayor parte del Senado huyeron a Grecia, donde se libró la decisiva batalla de Farsalia el 9 de agosto del 48 a.C., con victoria aplastante de César. Pompeyo huyó a Egipto, donde fue asesinado al desembarcar. César prosiguió la guerra en África (Tapso, 46 a.C.) e Hispania (Munda, 45 a.C.) hasta erradicar toda resistencia pompeyana, regresando a Roma como dictador vitalicio. Fue asesinado en los Idus de marzo del 44 a.C.',
'[{"pregunta":"¿Qué río cruzó César en 49 a.C.?","opciones":["Tíber","Rubicón","Po","Arno"],"correcta":1},{"pregunta":"¿Qué frase se atribuye a César en ese momento?","opciones":["Veni, vidi, vici","Alea iacta est","Et tu, Brute","Carthago delenda est"],"correcta":1},{"pregunta":"¿Dónde derrotó César a Pompeyo en 48 a.C.?","opciones":["Tapso","Farsalia","Munda","Alesia"],"correcta":1},{"pregunta":"¿Cuándo fue asesinado César?","opciones":["Idus de marzo del 44 a.C.","Kalendas de enero del 45 a.C.","Idus de junio del 44 a.C.","Nonas de marzo del 44 a.C."],"correcta":0}]'::jsonb),

('latin', 'bachillerato', '{2}', 'La educación romana: trivium y quadrivium',
'La educación romana estuvo inicialmente a cargo de los padres en el ámbito familiar: el pater familias enseñaba al hijo los valores tradicionales (mos maiorum), la agricultura, el manejo de las armas, los rudimentos del derecho y las costumbres religiosas. Con la progresiva helenización de Roma desde el siglo III a.C., se implantó un sistema educativo inspirado en el griego, organizado en varias etapas y a cargo de maestros pagados. La primera etapa era la escuela elemental (ludus litterarius), a la que asistían los niños y niñas entre los 7 y los 11-12 años, bajo la dirección del litterator o magister ludi. Aquí se aprendía a leer, escribir y los rudimentos del cálculo con ábaco. Los métodos eran memorísticos y frecuentemente brutales: los castigos corporales con la férula o la virga eran habituales, lo que suscitó protestas de pedagogos ilustrados como Quintiliano. La segunda etapa, a partir de los 12 años, era la escuela secundaria a cargo del grammaticus, donde se estudiaban los grandes autores latinos y griegos (especialmente Homero y Virgilio), con un análisis minucioso del texto: métrica, gramática, figuras retóricas, alusiones mitológicas e históricas. La tercera etapa, reservada a los jóvenes aristócratas que se preparaban para la carrera pública, era la escuela del rhetor, donde se aprendía el arte de la oratoria mediante ejercicios llamados declamaciones: se proponían temas ficticios (un joven hereda de un padre desconocido, una vestal juzgada) y los alumnos debían componer y pronunciar discursos siguiendo los cinco partes clásicas (inventio, dispositio, elocutio, memoria, actio). La influencia de este sistema pedagógico llegó a la Edad Media con el trivium (gramática, retórica, dialéctica) y el quadrivium (aritmética, geometría, astronomía, música), que conformaron las siete artes liberales medievales.',
'[{"pregunta":"¿Cómo se llamaba el maestro de escuela elemental?","opciones":["Grammaticus","Litterator o magister ludi","Rhetor","Paedagogus"],"correcta":1},{"pregunta":"¿Qué autores se estudiaban principalmente con el grammaticus?","opciones":["Cicerón y Séneca","Homero y Virgilio","Catulo y Ovidio","Marcial y Juvenal"],"correcta":1},{"pregunta":"¿Cómo se llamaban los ejercicios oratorios?","opciones":["Suasorias","Declamaciones","Controversias","Oratio"],"correcta":1},{"pregunta":"¿Qué formaba el trivium medieval?","opciones":["Aritmética, geometría, música","Gramática, retórica, dialéctica","Derecho, medicina, teología","Poesía, historia, filosofía"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'La Eneida: el libro IV y el amor de Dido',
'El libro IV de la Eneida es una de las páginas más conmovedoras de toda la literatura latina y una obra cumbre de la poesía amorosa y trágica. Narra la historia de amor entre Eneas, héroe troyano expulsado por el destino hacia Italia, y Dido, reina fundadora de Cartago, a cuyas costas los náufragos troyanos llegan al comienzo del libro I. Venus, madre de Eneas, para protegerlo, hace que Dido se enamore apasionadamente del héroe troyano. Durante los primeros meses, Eneas parece olvidar su misión divina y se deja llevar por la dulzura del amor y los lujos de la corte cartaginesa. El libro se abre con la célebre descripción de la herida de amor que corroe a la reina: At regina gravi iamdudum saucia cura vulnus alit venis et caeco carpitur igni (Pero la reina, desde hace tiempo herida por una grave preocupación, alimenta la herida en sus venas y es consumida por un fuego oculto). Juno y Venus conspiran para que ambos protagonistas consumen su unión durante una tormenta en una cueva, momento que Dido considera matrimonio pero que Eneas no reconoce como tal. Pronto, Júpiter envía a Mercurio para recordarle al héroe su destino imperial en Italia. Eneas, desgarrado pero obediente a los dioses, decide partir. Dido, al descubrir los preparativos secretos de la huida, se derrumba en una desesperación volcánica: implora, amenaza, maldice, alterna ternura y furor. Tras la partida de la flota troyana, la reina, incapaz de sobrevivir al abandono, ordena construir una pira y se da muerte con la espada regalada por Eneas, maldiciendo a todos los descendientes troyanos (prefiguración poética de las Guerras Púnicas). El libro IV es una meditación sobre el conflicto entre amor y deber, y uno de los momentos más humanos de toda la epopeya.',
'[{"pregunta":"¿Quién es Dido?","opciones":["Hermana de Eneas","Reina de Cartago","Diosa del amor","Sacerdotisa troyana"],"correcta":1},{"pregunta":"¿Qué diosa provoca el enamoramiento?","opciones":["Juno","Venus","Minerva","Diana"],"correcta":1},{"pregunta":"¿Quién ordena a Eneas continuar su viaje?","opciones":["Júpiter a través de Mercurio","Venus","Neptuno","La Sibila"],"correcta":0},{"pregunta":"¿Cómo muere Dido?","opciones":["Ahogada","Envenenada","Apuñalada con la espada de Eneas","De pena natural"],"correcta":2}]'::jsonb),

('latin', 'bachillerato', '{2}', 'La casa romana: domus, villa e insulae',
'Los romanos desarrollaron una rica variedad de tipologías arquitectónicas residenciales que reflejaban las diferencias sociales y las distintas necesidades urbanas y rurales. La casa aristocrática urbana se llamaba domus y estaba reservada a las familias más acomodadas, ya que ocupaba un solar entero de la ciudad y se extendía en horizontal, no en altura. Sus elementos principales eran, desde la entrada: vestibulum (vestíbulo entre la calle y la puerta), fauces (corredor), atrium (patio central descubierto con un estanque llamado impluvium bajo una abertura en el techo o compluvium, donde se recogía el agua de lluvia), tablinum (despacho del pater familias situado al fondo del atrio), peristylum (patio interior porticado, ajardinado, de inspiración griega helenística), cubicula (habitaciones), triclinium (comedor con tres lechos para cenar reclinados), culina (cocina), balneum (baño privado) y hortus (huerto posterior). Las paredes se decoraban con pinturas al fresco (de los cuatro estilos pompeyanos conocidos) y los suelos con mosaicos. La villa era la casa rural, residencia de campo donde los terratenientes se retiraban temporalmente y donde se explotaba la producción agrícola. Se distinguía entre villa rustica (propiamente agrícola) y villa urbana (de recreo, con lujos similares a los de la ciudad). Cicerón poseía varias villas en la costa campana. Por el contrario, la gran mayoría de los habitantes de Roma vivían en insulae, edificios de viviendas en altura, de tres a siete pisos, con apartamentos pequeños alquilados, construidos con materiales baratos (ladrillo y madera) y frecuentemente insalubres. Las plantas bajas solían contener tabernae (tiendas y talleres). Las insulae eran propensas a incendios, como el célebre del año 64 d.C. bajo Nerón.',
'[{"pregunta":"¿Cómo se llamaba el patio central de la domus?","opciones":["Peristilo","Atrio","Triclinio","Tablinum"],"correcta":1},{"pregunta":"¿Qué era el triclinium?","opciones":["El baño","La cocina","El comedor","La despensa"],"correcta":2},{"pregunta":"¿Cómo se llamaban los edificios de apartamentos?","opciones":["Domus","Villa","Insulae","Tabernae"],"correcta":2},{"pregunta":"¿Qué tipo de villa era de recreo?","opciones":["Villa rustica","Villa urbana","Villa marítima","Villa campestre"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'El ejército romano: legiones y conquista',
'El ejército fue el instrumento fundamental de la expansión romana y uno de los factores clave de la pervivencia del Imperio durante siglos. Su evolución fue lenta pero continua. En la época regia y arcaica, el ejército estaba formado por ciudadanos-soldados que acudían a la guerra con sus propios recursos y volvían al campo al final de la campaña. La organización original era la falange, similar a la griega. Tras la reforma de Camilo en el siglo IV a.C., se introdujo la legión manipular, con unidades más pequeñas y flexibles llamadas manípulos, mejor adaptadas al terreno itálico accidentado. La gran transformación del ejército romano se debe a Cayo Mario a finales del siglo II a.C. Enfrentado a la amenaza de los cimbrios y teutones y a la falta de voluntarios entre los propietarios agrarios, Mario abrió el alistamiento a los ciudadanos sin bienes (proletarii), a los que el Estado proporcionaría armamento, paga y tierras tras el licenciamiento. Creó además la legión cohortal (unidades de unos 480 hombres llamadas cohortes, diez por legión), introdujo el águila como estandarte común de cada legión (aquila), perfeccionó el entrenamiento y estableció el servicio por un plazo fijo. El nuevo ejército profesional era enormemente eficaz, pero también profundamente leal a su general, del que esperaba recompensas económicas: esta lealtad personal, más que a la República, facilitó las posteriores guerras civiles. Bajo el Imperio, Augusto reorganizó definitivamente el ejército en 28 legiones (luego reducidas) desplegadas en las fronteras, apoyadas por tropas auxiliares (auxilia) reclutadas entre los provinciales, la Guardia Pretoriana en Roma y la flota. Cada legión llevaba un número y un sobrenombre y sus soldados servían 20-25 años antes del licenciamiento con tierras o dinero.',
'[{"pregunta":"¿Quién profesionalizó el ejército romano?","opciones":["Camilo","Cayo Mario","Sila","César"],"correcta":1},{"pregunta":"¿Cuántos hombres formaban una cohorte?","opciones":["120","240","480","960"],"correcta":2},{"pregunta":"¿Qué animal era el estandarte principal de la legión?","opciones":["Lobo","Águila","León","Toro"],"correcta":1},{"pregunta":"¿Cómo se llamaban las tropas provinciales auxiliares?","opciones":["Legionarii","Auxilia","Foederati","Velites"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'La epopeya de Lucrecio: De rerum natura',
'Tito Lucrecio Caro (c. 99-55 a.C.) es el autor del poema filosófico más ambicioso de toda la literatura latina: De rerum natura (Sobre la naturaleza de las cosas), compuesto por seis libros en hexámetros y dedicado a su amigo Memmio. El propósito de la obra es exponer sistemáticamente la filosofía epicúrea en latín con una finalidad ética práctica: liberar al lector del miedo a los dioses y a la muerte, los dos grandes tormentos que, según los epicúreos, impedían al ser humano alcanzar la tranquilidad del ánimo (ataraxia). Lucrecio se presenta a sí mismo como discípulo ferviente de Epicuro, a quien considera un salvador del género humano y al que glorifica en los célebres proemios de cada libro. La estructura del poema es rigurosa: los dos primeros libros exponen la física atomista epicúrea, heredada de Demócrito: todo está compuesto de átomos indivisibles que se mueven en el vacío; nada se crea de la nada ni se destruye por completo; el universo es infinito y contiene múltiples mundos. Los libros III y IV tratan sobre el alma (mortal como el cuerpo, compuesta de átomos sutiles) y la percepción sensorial. Los libros V y VI abordan la cosmología (origen natural del mundo sin intervención divina), la antropología (desarrollo de las civilizaciones humanas) y los fenómenos meteorológicos, concluyendo con una impresionante descripción de la peste de Atenas durante la guerra del Peloponeso. La intención subyacente es demostrar que todos los fenómenos pueden explicarse por causas naturales, eliminando así la necesidad del miedo a los dioses. El poema combina la aridez conceptual de la filosofía con pasajes de enorme belleza lírica. Virgilio reconoce explícitamente la influencia de Lucrecio en sus propios versos.',
'[{"pregunta":"¿De cuántos libros consta De rerum natura?","opciones":["Tres","Cuatro","Seis","Nueve"],"correcta":2},{"pregunta":"¿Qué filosofía expone Lucrecio?","opciones":["Estoicismo","Epicureísmo","Escepticismo","Platonismo"],"correcta":1},{"pregunta":"¿Quién inspira la física atomista del poema?","opciones":["Aristóteles","Platón","Demócrito","Heráclito"],"correcta":2},{"pregunta":"¿Con qué descripción termina el poema?","opciones":["La peste de Atenas","Una batalla naval","El nacimiento de Roma","El amanecer"],"correcta":0}]'::jsonb),

('latin', 'bachillerato', '{2}', 'La satira latina: Marcial y Juvenal',
'La sátira es, según la famosa afirmación del retórico Quintiliano, un género completamente romano: satura quidem tota nostra est. Aunque hubo precedentes griegos de poesía burlesca, los romanos desarrollaron la sátira como género literario autónomo, dedicado a criticar los vicios, las costumbres y los personajes de su tiempo con un tono que podía ir del humor ligero a la indignación moral. Sus fundadores fueron Ennio y, sobre todo, Lucilio en el siglo II a.C., pero los grandes representantes de época imperial son Horacio (sátiras más benevolentes y morales), Persio (breve pero muy elaborado) y los dos máximos exponentes del género: Marcial y Juvenal. Marco Valerio Marcial (c. 40-104 d.C.), nacido en Bilbilis (Calatayud), se trasladó a Roma donde vivió modestamente durante casi cuarenta años dependiendo del patrocinio de los poderosos. Su gran obra son los Epigramas, colección de más de mil quinientos poemas breves en los que dibuja con humor agudo y a veces cruel la vida cotidiana romana: el cliente humillado esperando la sportula en casa del patrón, los snobs de la moda, los médicos incompetentes, los cazadores de herencias, los poetas malos, los matrimonios desiguales, las cortesanas, los barberos pesados. Inventó o perfeccionó el epigrama como género breve con un final sorpresivo (punctum) y su estilo influyó decisivamente en todos los epigramatistas posteriores. Décimo Junio Juvenal (c. 60-140 d.C.), posterior a Marcial, escribió dieciséis Sátiras en hexámetros dactílicos de tono mucho más amargo y severo, flagelando con indignación los vicios de la Roma imperial: la corrupción política, la decadencia moral, la hipocresía femenina, las ambiciones locas. Suyos son los versos inmortales Quis custodiet ipsos custodes? (¿Quién vigilará a los propios vigilantes?) y Mens sana in corpore sano.',
'[{"pregunta":"¿Quién afirmó que la sátira es un género completamente romano?","opciones":["Cicerón","Horacio","Quintiliano","Séneca"],"correcta":2},{"pregunta":"¿Dónde nació Marcial?","opciones":["Roma","Bilbilis","Córdoba","Gades"],"correcta":1},{"pregunta":"¿Cuántas Sátiras escribió Juvenal?","opciones":["Diez","Doce","Dieciséis","Veinte"],"correcta":2},{"pregunta":"¿De qué frase célebre es autor Juvenal?","opciones":["Carpe diem","Mens sana in corpore sano","Alea iacta est","Cogito ergo sum"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'La Roma de Augusto y el Principado',
'La instauración del régimen imperial romano se atribuye a Cayo Octavio, sobrino-nieto e hijo adoptivo de Julio César, conocido en la historia como Augusto. Tras el asesinato de César en el 44 a.C., Octavio formó el Segundo Triunvirato con Marco Antonio y Lépido, derrotó a los conjurados en Filipos (42 a.C.) y, progresivamente, fue eliminando a sus competidores. La victoria decisiva sobre Marco Antonio y Cleopatra en la batalla naval de Accio (2 de septiembre del 31 a.C.) le dejó como único dueño del mundo romano. A su regreso a Roma, Octavio ejerció un asombroso ejercicio de prudencia política: en el año 27 a.C. devolvió formalmente los poderes al Senado y al pueblo romano, declarando restaurada la República, pero el Senado, en gesto pactado, le concedió la supervisión de las provincias fronterizas (donde estaban las legiones) y le otorgó el honorífico título de Augustus. Comenzó así el llamado Principado, forma de gobierno en la que el emperador disimulaba formalmente su poder absoluto bajo el disfraz de las instituciones republicanas tradicionales. Augusto acumuló sucesivamente los poderes de cónsul, tribuno de la plebe, princeps senatus (primero del Senado), pontifex maximus y pater patriae, sin alterar las formas. Su reinado (27 a.C. - 14 d.C.) inauguró una paz de casi dos siglos (pax romana) y un florecimiento cultural excepcional (Virgilio, Horacio, Livio, Ovidio). Augusto promovió amplias obras públicas (Foro de Augusto, Mausoleo, Ara Pacis) y afirmaba: Marmoream se relinquere, quam latericiam accepisset (Dejo de mármol la ciudad que había recibido de ladrillo). Murió en Nola el 19 de agosto del 14 d.C., tras haber organizado cuidadosamente su sucesión en la persona de su hijastro Tiberio.',
'[{"pregunta":"¿Qué batalla naval ganó Augusto en 31 a.C.?","opciones":["Salamina","Accio","Milas","Nicópolis"],"correcta":1},{"pregunta":"¿Cuándo recibió el título de Augusto?","opciones":["31 a.C.","27 a.C.","23 a.C.","14 d.C."],"correcta":1},{"pregunta":"¿Cómo se llama el régimen que instauró?","opciones":["Dominado","Principado","Imperio","Tetrarquía"],"correcta":1},{"pregunta":"¿Qué se jactaba Augusto de haber hecho con Roma?","opciones":["Duplicarla","Dejarla de mármol","Reconquistarla","Repartirla"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'Suetonio y las Vidas de los Doce Césares',
'Cayo Suetonio Tranquilo (c. 70-130 d.C.) fue un escritor y biógrafo romano que sirvió como secretario personal (ab epistulis) del emperador Adriano hasta que cayó en desgracia. Amigo de Plinio el Joven y contemporáneo de Tácito, escribió numerosas obras entre las que destaca especialmente la colección De vita Caesarum, conocida en español como Vidas de los Doce Césares, biografía sucesiva de Julio César y los once primeros emperadores romanos: Augusto, Tiberio, Calígula, Claudio, Nerón, Galba, Otón, Vitelio, Vespasiano, Tito y Domiciano. La obra no es una historia política en el sentido moderno, sino una serie de retratos biográficos organizados según un esquema temático característico: nacimiento y familia, carrera política antes del poder, principales medidas como emperador, retrato físico y moral, costumbres, anécdotas curiosas y circunstancias de la muerte. Suetonio se distingue por su enorme erudición, su acceso a los archivos imperiales y su gusto por los detalles íntimos y pintorescos, incluyendo rumores escabrosos que otros historiadores omitían. Sus biografías de Calígula, Nerón o Domiciano son galerías de tiranías, extravagancias y crímenes, mientras que las de emperadores virtuosos como Augusto, Vespasiano o Tito son más equilibradas. Su estilo es claro, directo y libre de retórica, lo que lo hace especialmente accesible. Las Vidas de los Doce Césares fueron enormemente populares en la Antigüedad tardía y la Edad Media, sirviendo de modelo para la biografía histórica occidental y proporcionando la imagen canónica (y a menudo exageradamente negra) de los emperadores julio-claudios y flavios a la cultura moderna. Sin Suetonio, autores como Shakespeare (Julio César) o Robert Graves (Yo, Claudio) habrían sido inconcebibles.',
'[{"pregunta":"¿Cómo se titula su obra principal?","opciones":["Anales","De vita Caesarum","Historiae","Annales"],"correcta":1},{"pregunta":"¿Cuántos Césares biografía?","opciones":["Diez","Once","Doce","Trece"],"correcta":2},{"pregunta":"¿Qué cargo ocupó con Adriano?","opciones":["Cónsul","Prefecto","Secretario ab epistulis","Pretor"],"correcta":2},{"pregunta":"¿Qué autor moderno se inspiró en Suetonio para Yo, Claudio?","opciones":["Shakespeare","Robert Graves","Marguerite Yourcenar","Gore Vidal"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'Tito Livio y Ab Urbe condita',
'Tito Livio (59 a.C. - 17 d.C.) es el gran historiador del periodo augusteo y uno de los autores más representativos de la edad de oro de la prosa latina. Nacido en Patavium (Padua), ciudad famosa por su conservadurismo moral y por no haber sido nunca colonizada por Roma hasta fechas tardías, Livio se trasladó a Roma en su juventud y se dedicó enteramente a la escritura histórica, sin ocupar cargos políticos ni militares. Esta dedicación exclusiva al oficio de historiador era inusual en Roma, donde los grandes historiadores previos (César, Salustio) habían sido también hombres de Estado. Augusto lo recibió con honores y le confió la educación del futuro emperador Claudio, de quien despertó la afición a la historia. La obra monumental de Livio, titulada Ab Urbe condita libri, narra la historia de Roma desde la fundación legendaria de la ciudad (753 a.C.) hasta la muerte del general Druso Nerón Germánico en el 9 a.C. Originalmente constaba de 142 libros, que Livio dispuso en décadas (grupos de diez libros), como si fuera una obra en diez volúmenes. Desgraciadamente, solo se conservan 35 libros: los diez primeros (desde la fundación hasta 293 a.C.) y los libros XXI-XLV (desde el inicio de la Segunda Guerra Púnica, 218 a.C., hasta el 167 a.C., tras la victoria sobre Perseo de Macedonia). Del resto solo quedan resúmenes (periochae) antiguos. El estilo de Livio es cálido, patético y dramatizado: reconstruye la historia con discursos inventados para los personajes, escenas dialogadas, descripción viva de batallas y amplia presencia de anécdotas ejemplares. Su intención era moralizante: mostrar a los romanos de su tiempo, corrompidos por el lujo y el poder, el ejemplo de las virtudes primitivas de sus antepasados.',
'[{"pregunta":"¿Dónde nació Tito Livio?","opciones":["Roma","Patavium","Verona","Mantua"],"correcta":1},{"pregunta":"¿Cuántos libros componían originalmente su historia?","opciones":["50","100","142","200"],"correcta":2},{"pregunta":"¿Hasta qué acontecimiento llegaba la obra?","opciones":["Hasta César","Hasta la muerte de Druso (9 a.C.)","Hasta Augusto","Hasta Tiberio"],"correcta":1},{"pregunta":"¿A quién enseñó historia Livio?","opciones":["A Augusto","Al futuro emperador Claudio","A Tiberio","A Marco Aurelio"],"correcta":1}]'::jsonb),

('latin', 'bachillerato', '{2}', 'Las lenguas romances y el latín vulgar',
'Las lenguas romances (también llamadas neolatinas) son las lenguas vivas derivadas directamente del latín hablado en la Edad Media, tras la descomposición del Imperio Romano de Occidente. Las principales son el castellano, el catalán, el gallego, el portugués, el francés, el occitano, el italiano, el sardo, el retorromano y el rumano. Su fuente común no es el latín literario de Cicerón y Virgilio, sino lo que los filólogos llaman latín vulgar (sermo vulgaris), es decir, el latín hablado cotidianamente por los soldados, comerciantes, colonos y pueblo llano de las provincias, muy distinto del registro culto escrito. Este latín vulgar se caracterizaba por numerosas simplificaciones fonéticas, morfológicas y sintácticas respecto al clásico: pérdida de las cantidades vocálicas, reducción del sistema de declinaciones, desaparición de los casos y sustitución por preposiciones, simplificación del sistema verbal, sustitución de formas sintéticas por analíticas, uso creciente de auxiliares. También había importantes variaciones léxicas: el vulgar prefería palabras expresivas, concretas y frecuentemente diminutivas, a menudo de origen popular o incluso extranjero, frente a los términos cultos. Así, el clásico equus (caballo) fue sustituido en las provincias por caballus (jamelgo), que dio origen a cheval, caballo, cavallo, cavall. Igualmente, domus cedió lugar a casa (originalmente cabaña), os a bucca (boca), loqui a fabulare o parabolare. Cuando el Imperio se fragmentó y el contacto entre las provincias se debilitó, cada región fue desarrollando sus propias innovaciones, hasta que las variedades del latín vulgar se alejaron tanto que dejaron de ser mutuamente inteligibles y se convirtieron en lenguas distintas, aunque conservando siempre la estructura latina heredada. Los primeros textos en lenguas romances aparecen en el siglo IX (Juramentos de Estrasburgo, Glosas Silenses y Emilianenses).',
'[{"pregunta":"¿De qué registro del latín derivan las lenguas romances?","opciones":["Latín literario","Latín vulgar o sermo vulgaris","Latín arcaico","Latín medieval"],"correcta":1},{"pregunta":"¿Qué palabra sustituyó a equus?","opciones":["Cavallus","Caballus","Cavallo","Equinus"],"correcta":1},{"pregunta":"¿Qué palabra sustituyó a os (boca)?","opciones":["Labra","Bucca","Ora","Maxilla"],"correcta":1},{"pregunta":"¿Cuál NO es una lengua romance?","opciones":["Rumano","Sardo","Albanés","Retorromano"],"correcta":2}]'::jsonb),

('latin', 'bachillerato', '{2}', 'Quintiliano y la pedagogía romana',
'Marco Fabio Quintiliano (c. 35-100 d.C.), nacido en Calagurris (Calahorra, Hispania), es uno de los educadores y teóricos de la oratoria más importantes de la Antigüedad y probablemente el primer profesor público pagado por el Estado en la historia de Roma, cargo que recibió del emperador Vespasiano. Su obra fundamental, la Institutio oratoria, es el más completo tratado sobre la formación del orador que nos ha llegado desde el mundo antiguo. Consta de doce libros y expone de manera sistemática todo el proceso educativo del futuro orador desde la más tierna infancia hasta su perfeccionamiento como hombre público, pasando por las distintas etapas de la enseñanza y por un análisis minucioso de las cinco partes clásicas de la retórica (inventio, dispositio, elocutio, memoria, actio). Lo más notable de Quintiliano, que lo distingue de muchos educadores antiguos, es su pedagogía humanista y moderna. Defendía el aprendizaje desde una edad muy temprana, siempre en régimen de juego y sin castigos corporales, que rechazaba por considerarlos humillantes e ineficaces. Creía firmemente en la bondad natural del niño y en la importancia de adaptar la enseñanza a las capacidades individuales, lo que hoy llamaríamos educación personalizada. Insistía en la necesidad de que los profesores fueran moralmente ejemplares, pues consideraba que la buena formación no consistía solo en transmitir conocimientos, sino en modelar el carácter. Su ideal era el vir bonus dicendi peritus (hombre bueno experto en el hablar), definición de orador que combinaba la competencia técnica con la virtud ética. El libro X, dedicado a la formación literaria, contiene un extenso catálogo de autores griegos y latinos con juicios valiosísimos sobre cada uno. La Institutio fue redescubierta en el Renacimiento y tuvo enorme influencia en la pedagogía humanista de los siglos XV-XVII.',
'[{"pregunta":"¿Dónde nació Quintiliano?","opciones":["Roma","Córdoba","Calagurris","Gades"],"correcta":2},{"pregunta":"¿Cuántos libros tiene la Institutio oratoria?","opciones":["Ocho","Diez","Doce","Quince"],"correcta":2},{"pregunta":"¿Qué rechazaba Quintiliano en la educación?","opciones":["La lectura","Los castigos corporales","Los juegos","La memoria"],"correcta":1},{"pregunta":"¿Cuál era su ideal de orador?","opciones":["Vir doctus","Vir bonus dicendi peritus","Homo novus","Sapiens stoicus"],"correcta":1}]'::jsonb);

INSERT INTO comprension_texts (subject_id, level, grades, title, text_content, questions) VALUES
('latin', 'bachillerato', '{2}', 'Las Guerras Púnicas: Roma contra Cartago',
'Las Guerras Púnicas son tres grandes conflictos sucesivos que enfrentaron a Roma con Cartago entre los años 264 y 146 a.C., y que determinaron quién dominaría el Mediterráneo occidental. Su nombre proviene del término latino Poeni o Punici, con el que los romanos designaban a los fenicios y, por extensión, a los cartagineses, pueblo descendiente de colonos fenicios de Tiro. La Primera Guerra Púnica (264-241 a.C.) estalló por el control de Sicilia, y fue esencialmente una guerra naval. Roma, que hasta entonces no había tenido flota importante, construyó desde cero una armada y, gracias al uso del corvus (un puente de abordaje que convertía las batallas navales en enfrentamientos casi terrestres), logró derrotar a Cartago en batallas decisivas como la de las Islas Egates (241 a.C.). La paz obligó a Cartago a abandonar Sicilia, que se convirtió en la primera provincia romana. La Segunda Guerra Púnica (218-201 a.C.) es la más famosa y dramática. El general cartaginés Aníbal Barca, hijo de Amílcar, decidió atacar Italia por sorpresa desde Hispania, cruzando los Pirineos y, con enormes dificultades, los Alpes nevados al frente de un ejército que incluía elefantes. Durante quince años devastó Italia, obteniendo victorias memorables en Trebia, Trasimeno y especialmente Cannas (216 a.C.), donde aniquiló al mayor ejército romano jamás reunido. Roma, sin embargo, se recuperó gracias a una estrategia de desgaste (la política del dilator Fabio Máximo) y a que Escipión el Africano llevó la guerra a Hispania y luego a África, obligando a Aníbal a regresar para defender Cartago. La batalla final en Zama (202 a.C.) supuso la derrota definitiva de Aníbal. La Tercera Guerra Púnica (149-146 a.C.), impulsada por Catón con su célebre Ceterum censeo Carthaginem esse delendam (Además, opino que Cartago debe ser destruida), terminó con la destrucción completa de la ciudad.',
'[{"pregunta":"¿De dónde procede el término púnico?","opciones":["Del nombre griego","De los fenicios","De los etruscos","De los griegos"],"correcta":1},{"pregunta":"¿Qué dispositivo usaron los romanos en las batallas navales?","opciones":["El ariete","El corvus","La catapulta","El ancla"],"correcta":1},{"pregunta":"¿Dónde derrotó Aníbal al mayor ejército romano?","opciones":["Trebia","Trasimeno","Cannas","Zama"],"correcta":2},{"pregunta":"¿Quién pronunciaba Carthago delenda est?","opciones":["Escipión","Fabio Máximo","Catón el Viejo","Cicerón"],"correcta":2}]'::jsonb);





